DROP TABLE IF EXISTS `caixa`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `caixa` (
  `id` char(36) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `user_id` char(36) DEFAULT NULL,
  `data_fecho` datetime DEFAULT NULL,
  `valor_inicial` decimal(8,2) DEFAULT '0.00',
  `total_vendas` decimal(8,2) DEFAULT '0.00',
  `status` enum('Aberto','Fechado') DEFAULT 'Aberto',
  `observacoes` varchar(255) DEFAULT NULL,
  `total_caixa` decimal(10,2) DEFAULT NULL,
  `pos_id` char(36) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `caixa_deleted_at_index` (`deleted_at`),
  KEY `caixa_user_id_foreign` (`user_id`),
  KEY `caixa_pos_id_foreign` (`pos_id`),
