DROP TABLE IF EXISTS `cliente`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `cliente` (
  `id` char(36) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `tipo` enum('Pessoa Física','Pessoa Jurídica') DEFAULT NULL,
  `nome` varchar(255) DEFAULT NULL,
  `razao_social` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `telefone` varchar(255) DEFAULT NULL,
  `telefone_secundario` varchar(255) DEFAULT NULL,
  `nif` varchar(255) DEFAULT NULL,
  `numero_registro` varchar(255) DEFAULT NULL,
  `data_nascimento` date DEFAULT NULL,
  `genero` enum('Masculino','Feminino') DEFAULT NULL,
  `estado_civil` enum('Solteiro','Casado','Divorciado','Viúvo') DEFAULT NULL,
  `profissao` varchar(255) DEFAULT NULL,
  `website` varchar(255) DEFAULT NULL,
  `endereco` varchar(255) DEFAULT NULL,
  `bairro` varchar(255) DEFAULT NULL,
  `cidade` varchar(255) DEFAULT NULL,
  `provincia` varchar(255) DEFAULT NULL,
  `pais` varchar(255) DEFAULT NULL,
  `codigo_postal` varchar(255) DEFAULT NULL,
  `ativo` tinyint(1) DEFAULT NULL,
  `limite_credito` decimal(10,2) DEFAULT NULL,
  `saldo` decimal(10,2) DEFAULT NULL,
  `observacao` varchar(255) DEFAULT NULL,
  `logo` varchar(255) DEFAULT NULL,
  `foto` varchar(255) DEFAULT NULL,
  `cliente_pai_id` char(36) DEFAULT NULL,
  `empresa_id` char(36) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `cliente_deleted_at_index` (`deleted_at`),
  KEY `cliente_cliente_pai_id_foreign` (`cliente_pai_id`),
  KEY `cliente_empresa_id_index` (`empresa_id`),
  CONSTRAINT `cliente_cliente_pai_id_foreign` FOREIGN KEY (`cliente_pai_id`) REFERENCES `cliente` (`id`) ON DELETE SET NULL,
  CONSTRAINT `cliente_empresa_id_foreign` FOREIGN KEY (`empresa_id`) REFERENCES `empresa` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
