-- Table structure for table `verification_token_hash`
--

DROP TABLE IF EXISTS `verification_token_hash`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `verification_token_hash` (
  `id` char(36) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `user_id` char(36) DEFAULT NULL,
  `empresa_id` char(36) DEFAULT NULL,
  `verification_token_public` varchar(255) DEFAULT NULL,
  `verification_token_hash` varchar(255) DEFAULT NULL,
  `verification_token_expires_at` datetime DEFAULT NULL,
  `verified` tinyint(1) DEFAULT '0',
  `purpose` enum('account_activation','account_activation_reply_token','password_recovery') DEFAULT 'password_recovery',
  PRIMARY KEY (`id`),
  UNIQUE KEY `verification_token_hash_verification_token_public_unique` (`verification_token_public`),
  KEY `verification_token_hash_deleted_at_index` (`deleted_at`),
  KEY `verification_token_hash_user_id_foreign` (`user_id`),
  KEY `verification_token_hash_empresa_id_foreign` (`empresa_id`),
  CONSTRAINT `verification_token_hash_empresa_id_foreign` FOREIGN KEY (`empresa_id`) REFERENCES `empresa` (`id`) ON DELETE CASCADE,
  CONSTRAINT `verification_token_hash_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `user` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

